oxy_webhelp_navlinks = {"tocId-d30753e18558":{"topics":[{"title":"Microsoft Entra Domain mapping after moving subscriptions","shortdesc":"<p class=\"shortdesc\">After moving Azure subscriptions to a different Microsoft Entra Domain on the Azure         portal, you must update the domain mapping, upgrade permissions for the moved subscriptions         in <span class=\"ph\">RSC<\/span>, and recreate the Entra ID group within the new Microsoft Entra ID         domain to avoid data protection failures.<\/p>","href":"saas\/azr_entra_domain_mapping_moving_subs.html","attributes":{"data-id":"azr_entra_domain_mapping_moving_subs"},"menu":{"hasChildren":false},"tocID":"azr_entra_domain_mapping_moving_subs-d30753e18559","next":"azr_entra_domain_mapping_moving_subs-d30753e18559"},{"title":"Upgrading an Azure cloud account","shortdesc":"<p class=\"shortdesc\">Upgrade an Azure cloud account that is in the Update permissions state.<\/p>","href":"saas\/azr_upgrading_account.html","attributes":{"data-id":"azr_upgrading_account"},"menu":{"hasChildren":false},"tocID":"azr_upgrading_account-d30753e18601","next":"azr_upgrading_account-d30753e18601"},{"title":"Editing an Azure cloud account","shortdesc":"<p class=\"shortdesc\">Edit the details of an Azure cloud account configured <span class=\"ph\">with or         <\/span>without OAuth.<\/p>","href":"saas\/azr_editing_cloud_account.html","attributes":{"data-id":"azr_editing_cloud_account"},"menu":{"hasChildren":false},"tocID":"azr_editing_cloud_account-d30753e18626","topics":[]},{"title":"Editing an Exocompute subscription on Azure with OAuth","shortdesc":"<p class=\"shortdesc\">When using Microsoft Entra ID authentication, you can update an Exocompute on Azure         instance configured with OAuth.<\/p>","href":"saas\/azr_exocompute_editing_oauth.html","attributes":{"data-id":"azr_exocompute_editing_oauth"},"menu":{"hasChildren":false},"tocID":"azr_exocompute_editing_oauth-d30753e18640","topics":[]},{"title":"Editing Exocompute on Azure without OAuth","shortdesc":"<p class=\"shortdesc\">When you use Microsoft Entra ID authentication, edit the subscription name or group         object ID for Exocompute on an Azure instance configured without OAuth.<\/p>","href":"saas\/azr_exocompute_editing_wo_oauth.html","attributes":{"data-id":"azr_exocompute_editing_wo_oauth"},"menu":{"hasChildren":false},"tocID":"azr_exocompute_editing_wo_oauth-d30753e18651","topics":[]},{"title":"Updating permissions for management group subscriptions","shortdesc":"<p class=\"shortdesc\">Update permissions for all the Azure subscriptions that are onboarded using a         management group. For example, when a new release requires additional Azure         permissions.<\/p>","href":"saas\/azr_updating_perms_mgmt_grp_subs.html","attributes":{"data-id":"azr_updating_perms_mgmt_grp_subs"},"menu":{"hasChildren":false},"tocID":"azr_updating_perms_mgmt_grp_subs-d30753e18662","topics":[]},{"title":"Deleting an Azure cloud account","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Delete a cloud account if it is no longer protecting any Azure             virtual machines, disks, SQL DB, SQL MI, or Azure Blob Storage.<\/span><\/p>","href":"saas\/azr_deleting_account.html","attributes":{"data-id":"azr_deleting_account"},"menu":{"hasChildren":false},"tocID":"azr_deleting_account-d30753e18673","topics":[]},{"title":"Migrating existing Azure subscriptions to management group","shortdesc":"<p class=\"shortdesc\">Migrate existing individually onboarded Azure subscriptions to an Azure management         group to consolidate management and enable unified permission updates. The subscriptions         must already belong to the target management group in the Azure portal.<\/p>","href":"saas\/azr_migrating_existing_subs_mgmt_grp.html","attributes":{"data-id":"azr_migrating_existing_subs_mgmt_grp"},"menu":{"hasChildren":false},"tocID":"azr_migrating_existing_subs_mgmt_grp-d30753e18685","topics":[]},{"title":"Migrating existing Azure subscriptions to cloud discovery model","shortdesc":"<p class=\"shortdesc\">Migrate existing Azure subscriptions to the cloud discovery model by updating the         required permissions.<\/p>","href":"saas\/azr_migrating_existing_accounts_cloud_discovery_model.html","attributes":{"data-id":"azr_migrating_existing_accounts_cloud_discovery_model"},"menu":{"hasChildren":false},"tocID":"azr_migrating_existing_accounts_cloud_discovery_model-d30753e18696","topics":[]},{"title":"Disabling data scanning for Azure cloud accounts","shortdesc":"<p class=\"shortdesc\">Disable data scanning for an Azure account to stop the collection of data sensitivity         insights.<\/p>","href":"saas\/azure_disabling_data_scanning.html","attributes":{"data-id":"azure_disabling_data_scanning"},"menu":{"hasChildren":false},"tocID":"azure_disabling_data_scanning-d30753e18707","next":"azure_disabling_data_scanning-d30753e18707"},{"title":"Deleting cloud discovery for Azure","shortdesc":"<p class=\"shortdesc\">Delete cloud discovery when you want to remove an Azure account integration with <span class=\"ph\">RSC<\/span> or stop metadata collection.<\/p>","href":"saas\/azr_deleting_cloud_discovery.html","attributes":{"data-id":"azr_deleting_cloud_discovery"},"menu":{"hasChildren":false},"tocID":"azr_deleting_cloud_discovery-d30753e18743","topics":[]},{"title":"Azure permission validation","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides the permission validation feature to run on-demand         checks for all the Azure subscriptions added to <span class=\"ph\">RSC<\/span>, proactively identifying         missing permissions essential for protecting Azure workloads.<\/p>","href":"saas\/azr_perm_validation.html","attributes":{"data-id":"azr_perm_validation"},"menu":{"hasChildren":false},"tocID":"azr_perm_validation-d30753e18758","next":"azr_perm_validation-d30753e18758"}]}};